.breadcrumb a {
  color: #9a9a9a;
  font-size: 13px;
}
.breadcrumb a:hover {
  color: #e6e6e6;
  text-decoration: none;
}
.breadcrumb .separator {
  color: #3c3c3c;
  margin: 0 2px;
}

/* Search input */
.toolbar input[type="search"],
.toolbar input[type="text"] {
  background: #333337;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
  padding: 6px 10px;
  font-size: 13px;
  outline: none;
  box-sizing: border-box;
  margin-left: auto;
}
.toolbar input[type="search"]::placeholder,
.toolbar input[type="text"]::placeholder {
  color: #9a9a9a;
